class Solution {
public:
    int m, n, total;
    vector<int> indices;
    Solution(int m, int n) : m(m), n(n), total(m * n) {
        for (int i = 0; i < m; i++) {
            for (int j = 0; j < n; j++) {
                indices.push_back(i * n + j);
            }
        }
    }

    vector<int> flip() {
        int idx = rand() % total;
        int val = indices[idx];
        indices[idx] = indices[total - 1];
        total--;
        return {val / n, val % n};
    }

    void reset() {
        total = m * n;
        indices.clear();
        for (int i = 0; i < m; i++) {
            for (int j = 0; j < n; j++) {
                indices.push_back(i * n + j);
            }
        }
    }
};

